+
+func TestFindRuntime(t *testing.T) {
+	testLogger, _ := testlog.NewNullLogger()
+	logger.Logger = testLogger
+
+	testCases := []struct {
+		candidates   []string
+		expectedPath string
+	}{
+		{
+			candidates: []string{},
+		},
+		{
+			candidates: []string{"not-runc"},
+		},
+		{
+			candidates: []string{"not-runc", "also-not-runc"},
+		},
+		{
+			candidates:   []string{"runc"},
+			expectedPath: filepath.Join(cfg.root, "runc"),
+		},
+		{
+			candidates:   []string{"runc", "not-runc"},
+			expectedPath: filepath.Join(cfg.root, "runc"),
+		},
+		{
+			candidates:   []string{"not-runc", "runc"},
+			expectedPath: filepath.Join(cfg.root, "runc"),
+		},
+	}
+
+	for i, tc := range testCases {
+		runcPath, err := findRuntime(tc.candidates)
+		if tc.expectedPath == "" {
+			require.Error(t, err, "%d: %v", i, tc)
+		} else {
+			require.NoError(t, err, "%d: %v", i, tc)
+		}
+		require.Equal(t, tc.expectedPath, runcPath, "%d: %v", i, tc)
+	}
+
+}

commit c6b0b096f12471584eb603f5fbd0a21004aebd20
Author: Evan Lezar <elezar@nvidia.com>
Date:   Fri Apr 16 13:59:00 2021 +0200

    Refactor container runtime to use new packages

    This change refactors the NVIDIA container runtime to implement
    the oci.Runtime interface. A SyscallExec Runtime is used
    to encapsulate the calls to the underlying runtime (runc) and
    an oci.SpecModifier encapsulates the processing of the
    OCI specification.

    Modifications are still implemented in the existing addNVIDIAHooks
    function.

    The change also includes refactoring / reorganisation of the
    functions such as parsing of arguments and adds additional
    unit tests.

    Signed-off-by: Evan Lezar <elezar@nvidia.com>
